function solve(n: number, m: number, k: number): number {
    if (k === 0) {
        return n * m; // Each cell needs its own sensor
    }

    // If k is large enough to cover the entire grid, only one sensor is needed
    if (k >= Math.max(n, m) / 2) {
        return 1;
    }

    // For each row, we can place sensors in a pattern that covers the row
    // The number of sensors per row is ceil((m + 1) / (2 * k + 1))
    const sensorsPerRow = Math.ceil((m + 1) / (2 * k + 1));

    // The number of rows that need sensors is ceil((n + 1) / (2 * k + 1))
    const rowsWithSensors = Math.ceil((n + 1) / (2 * k + 1));

    return sensorsPerRow * rowsWithSensors;
}

